        function haversine(a,b){var R=6371000,dLat=(b[0]-a[0])*Math.PI/180,dLng=(b[1]-a[1])*Math.PI/180,lat1=a[0]*Math.PI/180,lat2=b[0]*Math.PI/180;var x=Math.sin(dLat/2)*Math.sin(dLat/2)+Math.cos(lat1)*Math.cos(lat2)*Math.sin(dLng/2)*Math.sin(dLng/2);return R*2*Math.atan2(Math.sqrt(x),Math.sqrt(1-x));}
        function fmtDist(m){return m<1000?(Math.round(m)+' m'):(m/1000).toFixed(2)+' km';}
        function downloadContoursKml(){var gj=window._contourGeojson;if(!gj||!gj.features||gj.features.length===0){alert('No contour data available.');return;}var NT='name';
            /* Detect whether this is isochrone or TARR data based on feature properties.
               Isochrone features have 'hours' and 'label'; TARR features have 'percentile'. */
            var isIso=gj.features[0]&&gj.features[0].properties.hours!==undefined;
            var docTitle=isIso?'Isochrone Contours':'TARR Percentile Contours';
            var docDesc=isIso?'Time-based reachability contours generated by WiSAR Decision Support Tool':'Terrain-Aware Range Rings generated by WiSAR Decision Support Tool';
            var kml='<?xml version="1.0" encoding="UTF-8"?>\n<kml xmlns="http://www.opengis.net/kml/2.2">\n<Document>\n<'+NT+'>'+docTitle+'</'+NT+'>\n<description>'+docDesc+'</description>\n';gj.features.forEach(function(f){var pname=isIso?(f.properties.label+' Isochrone'):(f.properties.percentile+' Percentile TARR');var styleId=isIso?('style_'+f.properties.hours):('style_'+f.properties.percentile);var descText=isIso?('Travel time: '+f.properties.hours+'h at flat-ground speed'):('Threshold: '+(f.properties.threshold_m/1000).toFixed(2)+' km cost-distance');var hex=f.properties.color.replace('#','');var r=parseInt(hex.substring(0,2),16),g=parseInt(hex.substring(2,4),16),b=parseInt(hex.substring(4,6),16);var kmlColor='00'+('0'+b.toString(16)).slice(-2)+('0'+g.toString(16)).slice(-2)+('0'+r.toString(16)).slice(-2);var lineColor='ff'+('0'+b.toString(16)).slice(-2)+('0'+g.toString(16)).slice(-2)+('0'+r.toString(16)).slice(-2);kml+='<Style id="'+styleId+'"><LineStyle><color>'+lineColor+'</color><width>2</width></LineStyle><PolyStyle><color>'+kmlColor+'</color></PolyStyle></Style>\n';var geom=f.geometry;var polys=[];if(geom.type==='Polygon'){polys=[geom.coordinates];}else if(geom.type==='MultiPolygon'){polys=geom.coordinates;}polys.forEach(function(rings){var coords=rings[0].map(function(c){return c[0]+','+c[1]+',0';}).join(' ');kml+='<Placemark><'+NT+'>'+pname+'</'+NT+'><description>'+descText+'</description><styleUrl>#'+styleId+'</styleUrl><Polygon><outerBoundaryIs><LinearRing><coordinates>'+coords+'</coordinates></LinearRing></outerBoundaryIs></Polygon></Placemark>\n';});});kml+='</Document>\n</kml>';var blob=new Blob([kml],{type:'application/vnd.google-earth.kml+xml'});var url=URL.createObjectURL(blob);var a=document.createElement('a');a.href=url;a.download=isIso?'isochrone_contours.kml':'tarr_contours.kml';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);}
        function downloadContoursGeojson(){var gj=window._contourGeojson;if(!gj||!gj.features||gj.features.length===0){alert('No contour data available.');return;}var isIso=gj.features[0]&&gj.features[0].properties.hours!==undefined;var blob=new Blob([JSON.stringify(gj,null,2)],{type:'application/geo+json'});var url=URL.createObjectURL(blob);var a=document.createElement('a');a.href=url;a.download=isIso?'isochrone_contours.geojson':'tarr_contours.geojson';document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);}
        function setCaltopoExportStatus(type,msg){var el=document.getElementById('caltopoExportStatus');el.style.display='block';el.style.background=type==='success'?'rgba(34,197,94,0.1)':type==='error'?'rgba(239,68,68,0.1)':'rgba(59,130,246,0.1)';el.style.color=type==='success'?'var(--success)':type==='error'?'#ef4444':'var(--accent)';el.style.border='1px solid '+(type==='success'?'rgba(34,197,94,0.3)':type==='error'?'rgba(239,68,68,0.3)':'rgba(59,130,246,0.3)');el.textContent=msg;}

        // Show/hide the credentials sub-section based on the team radio
        // selection. CCSO mode uses server-side env-var credentials; Other
        // mode reveals the three input fields for user-supplied credentials.
        function onCaltopoTeamChange(){
            var teamRadio = document.querySelector('input[name="caltopoTeam"]:checked');
            var team = teamRadio ? teamRadio.value : 'ccso';
            var credsRow = document.getElementById('caltopoCredsRow');
            if (credsRow) {
                credsRow.style.display = (team === 'other') ? 'block' : 'none';
            }
            // Clear any prior status message so the user isn't confused by
            // a stale "exported successfully" or "failed" notice when they
            // switch teams.
            var statusEl = document.getElementById('caltopoExportStatus');
            if (statusEl) statusEl.style.display = 'none';
        }

        async function exportTarrsToCalTopo() {
            var gj = window._contourGeojson;
            if (!gj || !gj.features || gj.features.length === 0) {
                setCaltopoExportStatus('error', 'No contours available to export.');
                return;
            }
            var mapId = document.getElementById('caltopoExportMapId').value.trim();
            if (!mapId) {
                setCaltopoExportStatus('error', 'Enter a CalTopo Map ID to export to.');
                return;
            }

            // Read team selection and assemble the request body. CCSO mode
            // sends just {team, map_id, contours} — server uses env-var
            // credentials. Other mode sends the three credential fields too;
            // server passes them through to CalTopo without persisting.
            var teamRadio = document.querySelector('input[name="caltopoTeam"]:checked');
            var team = teamRadio ? teamRadio.value : 'ccso';
            var body = { team: team, map_id: mapId, contours: gj };

            if (team === 'other') {
                var accountId = document.getElementById('caltopoAccountId').value.trim();
                var credentialId = document.getElementById('caltopoCredentialId').value.trim();
                var credentialKey = document.getElementById('caltopoCredentialKey').value.trim();
                if (!accountId || !credentialId || !credentialKey) {
                    setCaltopoExportStatus('error',
                        'Enter all three credentials (Account ID, Credential ID, Credential Key) for your team.');
                    return;
                }
                body.account_id = accountId;
                body.credential_id = credentialId;
                body.credential_key = credentialKey;
            }

            var btn = document.getElementById('exportTarrsBtn');
            var isIso = gj.features[0] && gj.features[0].properties.hours !== undefined;
            var label = isIso ? 'contours' : 'TARRs';
            btn.disabled = true;
            btn.innerHTML = '<span class="spinner"></span> Exporting ' + label + '...';
            setCaltopoExportStatus('info', 'Pushing ' + gj.features.length + ' ' + label + ' to CalTopo...');

            try {
                var resp = await fetch('/api/caltopo/export-tarrs', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(body)
                });
                var data = await resp.json();
                if (data.status === 'ok') {
                    var okCount = data.results.filter(function(r){return r.status==='ok';}).length;
                    setCaltopoExportStatus('success',
                        'Exported ' + okCount + '/' + gj.features.length + ' ' + label +
                        ' to CalTopo map ' + mapId);
                } else if (data.status === 'auth_error') {
                    // Surfaced distinctly so the user knows to check credentials
                    // rather than network/server issues.
                    setCaltopoExportStatus('error',
                        'CalTopo rejected the credentials. Double-check Account ID, ' +
                        'Credential ID, and Credential Key.');
                } else {
                    setCaltopoExportStatus('error',
                        'Export failed: ' + (data.message || 'Unknown error'));
                }
            } catch (err) {
                setCaltopoExportStatus('error', 'Export failed: ' + err.message);
            }
            btn.disabled = false;
            btn.textContent = isIso ? 'Export Contours to CalTopo' : 'Export TARRs to CalTopo';
        }
        function toggleMeasure(){measureMode=!measureMode;var btn=document.getElementById('measureBtn');if(measureMode){btn.classList.add('active');document.getElementById('map').style.cursor='crosshair';if(ippPlaceMode){ippPlaceMode=false;document.getElementById('ippDropBtn').style.borderColor='var(--border)';document.getElementById('ippDropBtn').style.background='var(--bg-field)';}}else{btn.classList.remove('active');document.getElementById('map').style.cursor='';clearMeasure();}}
