        function placeIPP(lat,lng,source){if(ippMarker)map.removeLayer(ippMarker);ippMarker=L.marker([lat,lng],{icon:ippIcon,draggable:true}).addTo(map).bindPopup('<div class="popup-title">Initial Planning Point</div><div class="popup-detail">Lat: '+lat.toFixed(6)+'<br>Lng: '+lng.toFixed(6)+'<br>Source: '+source+'<br><em>Drag to reposition</em></div>');document.getElementById('ippInput').value=lat.toFixed(6)+', '+lng.toFixed(6);ippMarker.on('dragend',function(e){var pos=e.target.getLatLng();document.getElementById('ippInput').value=pos.lat.toFixed(6)+', '+pos.lng.toFixed(6);ippMarker.setPopupContent('<div class="popup-title">Initial Planning Point</div><div class="popup-detail">Lat: '+pos.lat.toFixed(6)+'<br>Lng: '+pos.lng.toFixed(6)+'<br>Source: Repositioned<br><em>Drag to reposition</em></div>');setIppStatus('success','IPP moved to '+pos.lat.toFixed(4)+', '+pos.lng.toFixed(4));if(window.onIppPlaced)window.onIppPlaced(pos.lat,pos.lng,'Repositioned');});checkRunButton();if(typeof checkIsoRunButton==='function')checkIsoRunButton();if(window.onIppPlaced)window.onIppPlaced(lat,lng,source);}
        
        function setIPP(){var raw=document.getElementById('ippInput').value.trim();if(!raw){setIppStatus('error','Enter coordinates as: latitude, longitude');return;}var parts=raw.split(',').map(function(s){return parseFloat(s.trim());});if(parts.length!==2||isNaN(parts[0])||isNaN(parts[1])){setIppStatus('error','Invalid format. Use: 34.9200, -111.9100');return;}var lat=parts[0],lng=parts[1];if(lat<-90||lat>90||lng<-180||lng>180){setIppStatus('error','Coordinates out of range.');return;}placeIPP(lat,lng,'Manual entry');map.setView([lat,lng],14);setIppStatus('success','IPP set at '+lat.toFixed(4)+', '+lng.toFixed(4));}
