        function onCategoryChange(){var cat=document.getElementById('lpbCategory').value;lpbSelectedEco=null;lpbSelectedTerrain=null;document.getElementById('lpbEcoRow').classList.add('hidden');document.getElementById('lpbTerrainRow').classList.add('hidden');document.getElementById('lpbSource').classList.add('hidden');document.getElementById('calibrationIndicator').classList.add('hidden');if(!cat){document.getElementById('pct25').value='';document.getElementById('pct50').value='';document.getElementById('pct75').value='';checkRunButton();return;}var entries=LPB_DATA[cat];var ecos=[];entries.forEach(function(e){if(e.eco&&ecos.indexOf(e.eco)<0)ecos.push(e.eco);});if(ecos.length===0){applyLPB(cat,null,null);return;}var ecoDiv=document.getElementById('lpbEcoBtns');ecoDiv.innerHTML='';ecos.forEach(function(eco){var btn=makeLpbBtn(eco,function(){lpbSelectedEco=eco;highlightBtn(ecoDiv,btn);onEcoChange(cat,eco);});ecoDiv.appendChild(btn);});if(entries.some(function(e){return e.eco===null;})){var btn=makeLpbBtn('Other/Default',function(){lpbSelectedEco=null;highlightBtn(ecoDiv,btn);applyLPB(cat,null,null);document.getElementById('lpbTerrainRow').classList.add('hidden');});ecoDiv.appendChild(btn);}document.getElementById('lpbEcoRow').classList.remove('hidden');document.getElementById('lpbTerrainRow').classList.add('hidden');}
        function onEcoChange(cat,eco){lpbSelectedTerrain=null;var entries=LPB_DATA[cat].filter(function(e){return e.eco===eco;});var terrains=[];entries.forEach(function(e){if(e.terrain&&terrains.indexOf(e.terrain)<0)terrains.push(e.terrain);});if(terrains.length===0){applyLPB(cat,eco,null);document.getElementById('lpbTerrainRow').classList.add('hidden');return;}var tDiv=document.getElementById('lpbTerrainBtns');tDiv.innerHTML='';terrains.forEach(function(t){var btn=makeLpbBtn(t,function(){lpbSelectedTerrain=t;highlightBtn(tDiv,btn);applyLPB(cat,eco,t);});tDiv.appendChild(btn);});if(entries.some(function(e){return e.terrain===null;})){var btn=makeLpbBtn('Other/Default',function(){lpbSelectedTerrain=null;highlightBtn(tDiv,btn);applyLPB(cat,eco,null);});tDiv.appendChild(btn);}document.getElementById('lpbTerrainRow').classList.remove('hidden');}
        function applyLPB(cat,eco,terrain){var entries=LPB_DATA[cat];var match=entries.find(function(e){return e.eco===eco&&e.terrain===terrain;});if(!match)match=entries.find(function(e){return e.eco===eco&&e.terrain===null;});if(!match)match=entries.find(function(e){return e.eco===null&&e.terrain===null;});if(!match)match=entries[entries.length-1];document.getElementById('pct25').value=match.distances[0];document.getElementById('pct50').value=match.distances[1];document.getElementById('pct75').value=match.distances[2];document.getElementById('lpbSource').classList.remove('hidden');var calDiv=document.getElementById('calibrationIndicator');var cal=CALIBRATION_MULTIPLIERS[cat]||CALIBRATION_DEFAULT;var isProfile=!!CALIBRATION_MULTIPLIERS[cat];calDiv.textContent='Coconino calibration: \u00d7'+cal.m25.toFixed(2)+' / \u00d7'+cal.m50.toFixed(2)+' / \u00d7'+cal.m75.toFixed(2)+' (p25/p50/p75)'+(isProfile?' \u2014 profile-specific':' \u2014 global default');calDiv.classList.remove('hidden');checkRunButton();}
        /* ----------------------------------------------------------
           clearAnalysisState: shared state reset for switchMode and resetTool.

           Both functions used to be ~95% duplicates and drifted apart over
           time (the IPP-button style reset existed in resetTool but was
           missing from switchMode, causing the Drop Pin button to remain
           highlighted across a mode switch). Anything that should always
           happen when wiping the current analysis goes here.
           ---------------------------------------------------------- */
        function clearAnalysisState(){
            clearMeasure();
            if(measureMode){measureMode=false;document.getElementById('measureBtn').classList.remove('active');}
            if(window.costOverlay)map.removeLayer(window.costOverlay);
            if(window.pctOverlay)map.removeLayer(window.pctOverlay);
            if(window.terrainOverlay)map.removeLayer(window.terrainOverlay);
            window.costOverlay=null;window.pctOverlay=null;window.terrainOverlay=null;
            contourLayer.clearLayers();
            if(ippMarker)map.removeLayer(ippMarker);
            ippMarker=null;
            segmentLayer.clearLayers();
            map.setView([35.2,-111.65],10);
            document.getElementById('layerToggles').classList.add('hidden');
            document.getElementById('downloadSection')&&(document.getElementById('downloadSection').classList.add('hidden'));
            document.getElementById('caltopoExportSection')&&(document.getElementById('caltopoExportSection').style.display='none');
            document.getElementById('exportTarrsBtn')&&(document.getElementById('exportTarrsBtn').style.display='none');
            document.getElementById('caltopoExportStatus')&&(document.getElementById('caltopoExportStatus').style.display='none');
            if(document.getElementById('caltopoExportMapId'))document.getElementById('caltopoExportMapId').value='';
            // Reset the CalTopo team selector to CCSO and clear any
            // user-entered "Other Team" credentials. Per design, credentials
            // never persist — every session starts with the CCSO default
            // and empty credential fields if the user switches to Other.
            var ccsoRadio=document.querySelector('input[name="caltopoTeam"][value="ccso"]');
            if(ccsoRadio)ccsoRadio.checked=true;
            var credsRow=document.getElementById('caltopoCredsRow');
            if(credsRow)credsRow.style.display='none';
            if(document.getElementById('caltopoAccountId'))document.getElementById('caltopoAccountId').value='';
            if(document.getElementById('caltopoCredentialId'))document.getElementById('caltopoCredentialId').value='';
            if(document.getElementById('caltopoCredentialKey'))document.getElementById('caltopoCredentialKey').value='';
            window._contourGeojson=null;
            document.getElementById('analysisStatusBar').className='status-bar';
            document.getElementById('ippStatusBar').className='status-bar';
            document.getElementById('isoStatusBar')&&(document.getElementById('isoStatusBar').className='status-bar');
            document.getElementById('pct25').value='';
            document.getElementById('pct50').value='';
            document.getElementById('pct75').value='';
            document.getElementById('lpbCategory').selectedIndex=0;
            lpbSelectedEco=null;
            lpbSelectedTerrain=null;
            document.getElementById('lpbEcoRow').classList.add('hidden');
            document.getElementById('lpbTerrainRow').classList.add('hidden');
            document.getElementById('lpbSource').classList.add('hidden');
            document.getElementById('calibrationIndicator').classList.add('hidden');
            document.getElementById('coordEntryDiv').classList.add('hidden');
            document.getElementById('dropPinDiv').classList.add('hidden');
            if(document.getElementById('isoSpeed'))document.getElementById('isoSpeed').value='';
            document.querySelectorAll('.iso-interval').forEach(function(cb){cb.checked=true;});
            document.getElementById('map').style.cursor='';
            ippPlaceMode=false;
            // Reset IPP method-selector buttons to their default (un-highlighted)
            // state. Without this, a highlighted Drop Pin / Coord Entry button
            // persists across mode switches and resets.
            document.getElementById('ippDropBtn').style.borderColor='var(--border)';
            document.getElementById('ippDropBtn').style.background='var(--bg-field)';
            document.getElementById('ippCoordBtn').style.borderColor='var(--border)';
            document.getElementById('ippCoordBtn').style.background='var(--bg-field)';
            checkRunButton();
            clearDataWarnings('analysisDataWarnings');
            clearDataWarnings('isoDataWarnings');
            if(window.onToolReset)window.onToolReset();
        }
        function switchMode(){
            clearAnalysisState();
            document.getElementById('splashModal').classList.remove('hidden');
        }
        function resetTool(){
            clearAnalysisState();
            setIppStatus('info','IPP cleared. Choose a method above to set a new one.');
        }
        function showCoordEntry(){document.getElementById('coordEntryDiv').classList.remove('hidden');document.getElementById('dropPinDiv').classList.add('hidden');document.getElementById('ippCoordBtn').style.borderColor='var(--accent)';document.getElementById('ippCoordBtn').style.background='var(--accent-glow)';document.getElementById('ippDropBtn').style.borderColor='var(--border)';document.getElementById('ippDropBtn').style.background='var(--bg-field)';ippPlaceMode=false;document.getElementById('map').style.cursor='';}
        function activateDropPin(){document.getElementById('dropPinDiv').classList.remove('hidden');document.getElementById('coordEntryDiv').classList.add('hidden');document.getElementById('ippDropBtn').style.borderColor='var(--accent)';document.getElementById('ippDropBtn').style.background='var(--accent-glow)';document.getElementById('ippCoordBtn').style.borderColor='var(--border)';document.getElementById('ippCoordBtn').style.background='var(--bg-field)';ippPlaceMode=true;document.getElementById('map').style.cursor='crosshair';setIppStatus('info','Click on the map to place the IPP.');}
        var ippPlaceMode=false;map.on('click',function(e){if(measureMode){addMeasurePoint(e.latlng);return;}if(!currentMode||!ippPlaceMode)return;placeIPP(e.latlng.lat,e.latlng.lng,'Map click');setIppStatus('success','IPP placed at '+e.latlng.lat.toFixed(4)+', '+e.latlng.lng.toFixed(4));ippPlaceMode=false;document.getElementById('map').style.cursor='';document.getElementById('dropPinHint').textContent='IPP placed. Click the map again to move it, or proceed below.';document.getElementById('ippDropBtn').style.borderColor='var(--success)';document.getElementById('ippDropBtn').style.background='rgba(34,197,94,0.1)';});
        function runAnalysis(){var p25=parseFloat(document.getElementById('pct25').value)||0,p50=parseFloat(document.getElementById('pct50').value)||0,p75=parseFloat(document.getElementById('pct75').value)||0;if(p25<=0||p50<=0||p75<=0||p25>=p50||p50>=p75){setAnalysisStatus('error','Select a subject profile to set percentiles.');return;}var profileName=document.getElementById('lpbCategory').value||'';var cal=profileName?(CALIBRATION_MULTIPLIERS[profileName]||CALIBRATION_DEFAULT):CALIBRATION_DEFAULT;var cal_p25=p25*cal.m25;var cal_p50=p50*cal.m50;var cal_p75=p75*cal.m75;var ipp=ippMarker.getLatLng();var params={ipp:{lat:ipp.lat,lng:ipp.lng}};if(profileName){params.profile=profileName;}params.percentiles={p25:cal_p25,p50:cal_p50,p75:cal_p75};document.getElementById('runBtn').disabled=true;
            if(window.onAnalysisStart)window.onAnalysisStart();
            var msgs=['Calculating bounding box...','Downloading elevation data (USGS 3DEP)...','Downloading land cover data (NLCD)...','Downloading trails, roads, power lines, and waterways (OSM)...','Building friction surface from land cover...','Burning in trails, roads, and power line corridors...','Running anisotropic cost-distance from IPP (this is the slow step)...','Generating probability surface...'];
            var msgIdx=0;
            setAnalysisStatus('info',msgs[0]);
            var progressTimer=setInterval(function(){msgIdx++;if(msgIdx<msgs.length){setAnalysisStatus('info',msgs[msgIdx]);}else{setAnalysisStatus('info','Still processing... almost there.');}},8000);fetch('/api/analyze',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(params)}).then(function(r){return r.json();}).then(function(data){if(data.status!=='ok')throw new Error(data.message);setAnalysisStatus('success','Analysis complete. Use layer toggles to explore.');renderDataWarnings('analysisDataWarnings',data.warnings||[]);
                /* Restore TARR-specific labels in case a previous isochrone run
                   changed them to travel time terminology */
                document.getElementById('pctToggle').parentElement.lastChild.textContent=' Percentile Contours (TARRs)';
                document.getElementById('dlContoursKml').textContent='Percentile Contours (KML)';
                document.getElementById('dlContoursGeojson').textContent='Percentile Contours (GeoJSON)';
                document.getElementById('exportTarrsBtn').textContent='Export TARRs to CalTopo';
                /* Restore the default TARR legend content in case travel time
                   mode previously overwrote it with isochrone swatches.
                   On the first TARR run, capture the legend HTML as the default
                   so we have it for future restores. */
                var legendBody=document.getElementById('legendBody');
                if(legendBody){
                    if(_defaultLegendHtml===null){
                        // First TARR run — save the current (original) legend as default
                        _defaultLegendHtml=legendBody.innerHTML;
                    }else{
                        // Subsequent runs — restore the saved default
                        legendBody.innerHTML=_defaultLegendHtml;
                    }
                    legendBody.classList.remove('open');
                }
                document.getElementById('downloadSection').classList.remove('hidden');
                document.getElementById('dlCostPng').href='/api/results/'+data.analysis_id+'/cost_surface.png';
                document.getElementById('dlTerrainPng').href='/api/results/'+data.analysis_id+'/terrain.png';
                document.getElementById('dlCostDist').href='/api/results/'+data.analysis_id+'/cost_distance.tif';
                document.getElementById('dlCostSurf').href='/api/results/'+data.analysis_id+'/cost_surface.tif';
                if(window.onAnalysisComplete)window.onAnalysisComplete();
                // Percentile-specific download links and CalTopo export UI.
                // Only shown when the backend actually generated probability
                // contours (i.e., TARR mode runs with valid percentiles).
                if(data.has_percentiles){
                    document.getElementById('dlPctPng').style.display='block';
                    document.getElementById('dlPctPng').href='/api/results/'+data.analysis_id+'/percentiles.png';
                    document.getElementById('dlProb').style.display='block';
                    document.getElementById('dlProb').href='/api/results/'+data.analysis_id+'/probability.tif';
                    if(data.contour_geojson){
                        window._contourGeojson=data.contour_geojson;
                        document.getElementById('dlContoursKml').style.display='block';
                        document.getElementById('dlContoursGeojson').style.display='block';
                        document.getElementById('caltopoExportSection').style.display='block';
                        document.getElementById('exportTarrsBtn').style.display='block';
                        document.getElementById('caltopoExportMapIdRow').style.display='block';
                    }else{
                        document.getElementById('dlContoursKml').style.display='none';
                        document.getElementById('dlContoursGeojson').style.display='none';
                        document.getElementById('caltopoExportSection').style.display='none';
                    }
                }
                document.getElementById('caltopoExportStatus').style.display='none';

                // --- Map overlays ---
                var bounds=[[data.bounds.south,data.bounds.west],[data.bounds.north,data.bounds.east]];
                if(window.costOverlay){map.removeLayer(window.costOverlay);}
                if(window.pctOverlay){map.removeLayer(window.pctOverlay);}
                contourLayer.clearLayers();
                var aid=data.analysis_id;
                window.costOverlay=L.imageOverlay('/api/results/'+aid+'/cost_surface.png?t='+Date.now(),bounds,{opacity:0.6});
                window.pctOverlay=null;
                if(window.terrainOverlay){map.removeLayer(window.terrainOverlay);}
                window.terrainOverlay=L.imageOverlay('/api/results/'+aid+'/terrain.png?t='+Date.now(),bounds,{opacity:0.6});

                // Once the cost-surface PNG has loaded, draw the percentile
                // contour outlines and their labels on top. Each contour is
                // drawn twice: a dark "halo" underneath, then the colored line
                // on top. The halo gives the colored line a contrast boundary
                // so it reads clearly against the busy Jacobs heatmap
                // background regardless of what color is underneath.
                window.costOverlay.on('load',function(){
                    if(data.has_percentiles&&data.contour_geojson){
                        contourLayer.clearLayers();
                        data.contour_geojson.features.forEach(function(f){
                            // Dark halo underneath — wider, semi-transparent black
                            var halo={color:'#1a1a1a',weight:6,opacity:0.6,fillOpacity:0};
                            contourLayer.addLayer(L.geoJSON(f,{style:halo}));
                            // Colored line on top
                            var style={
                                color:f.properties.color,
                                weight:3,
                                opacity:1.0,
                                fillColor:f.properties.color,
                                fillOpacity:0,
                                dashArray:null
                            };
                            var layer=L.geoJSON(f,{style:style});
                            contourLayer.addLayer(layer);
                            var labelIcon=L.divIcon({
                                className:'',
                                html:'<div style="background:rgba(30,30,30,0.65);color:'+f.properties.color+';padding:4px 12px;border-radius:4px;font-size:13px;font-weight:700;font-family:sans-serif;white-space:nowrap;letter-spacing:0.5px;line-height:1;text-align:center;min-width:36px;">'+f.properties.percentile+'</div>',
                                iconSize:[null,null],
                                iconAnchor:[0,12],
                                iconAnchor:[0,10]
                            });
                            var bounds=layer.getBounds();
                            var labelLat=f.properties.label_lat||bounds.getCenter().lat;
                            var labelLng=bounds.getEast();
                            contourLayer.addLayer(L.marker([labelLat,labelLng],{icon:labelIcon,interactive:false}));
                        });
                    }
                });
                window.costOverlay.addTo(map);
                map.fitBounds(bounds);

                // Layer toggles
                document.getElementById('layerToggles').classList.remove('hidden');
                document.getElementById('costToggle').checked=true;
                document.getElementById('costToggle').parentElement.style.opacity='1';
                document.getElementById('pctToggle').checked=data.has_percentiles;
                if(!data.has_percentiles){
                    document.getElementById('pctToggle').disabled=true;
                    document.getElementById('pctToggle').parentElement.style.opacity='0.4';
                }else{
                    document.getElementById('pctToggle').disabled=false;
                    document.getElementById('pctToggle').parentElement.style.opacity='1';
                }
                clearInterval(progressTimer);
                document.getElementById('runBtn').disabled=false;
            }).catch(function(err){
                setAnalysisStatus('error','Failed: '+err.message);
                clearInterval(progressTimer);
                document.getElementById('runBtn').disabled=false;
            });
        }
        /* ============================================================
           Isochrone mode — helper functions and analysis runner
           
           These functions support the second analysis mode: time-based
           reachability isochrones. The coordinator specifies a flat-
           ground travel speed and time intervals, and the tool shows
           where a subject could physically be after each time period.
           ============================================================ */

        /* Track the active speed unit so we can convert correctly.
           US SAR coordinators default to mph; the backend expects km/h. */
        var isoSpeedUnit='mph';

        /**
         * Toggle between mph and km/h display in the speed input.
         * Converts the current value to the new unit so the number
         * shown always reflects the selected unit.
         */
        function setIsoUnit(unit){
            var input=document.getElementById('isoSpeed');
            var val=parseFloat(input.value);
            if(unit==='mph'){
                document.getElementById('isoUnitMph').style.background='var(--accent)';
                document.getElementById('isoUnitMph').style.color='white';
                document.getElementById('isoUnitKmh').style.background='var(--bg-field)';
                document.getElementById('isoUnitKmh').style.color='var(--text-secondary)';
                // Convert km/h -> mph if switching from kmh
                if(isoSpeedUnit==='kmh'&&!isNaN(val)&&val>0){
                    input.value=(val/1.609344).toFixed(1);
                }
            }else{
                document.getElementById('isoUnitKmh').style.background='var(--accent)';
                document.getElementById('isoUnitKmh').style.color='white';
                document.getElementById('isoUnitMph').style.background='var(--bg-field)';
                document.getElementById('isoUnitMph').style.color='var(--text-secondary)';
                // Convert mph -> km/h if switching from mph
                if(isoSpeedUnit==='mph'&&!isNaN(val)&&val>0){
                    input.value=(val*1.609344).toFixed(1);
                }
            }
            isoSpeedUnit=unit;
            checkIsoRunButton();
        }

        /**
         * Apply a speed preset — sets the value and ensures the unit
         * matches the preset's native unit (always mph for our presets).
         */
        function setIsoSpeedPreset(value,unit){
            if(isoSpeedUnit!==unit)setIsoUnit(unit);
            document.getElementById('isoSpeed').value=value;
            checkIsoRunButton();
        }

        /**
         * Enable/disable the isochrone Run button based on whether
         * the user has placed an IPP and entered a valid speed.
         */
        function checkIsoRunButton(){
            var btn=document.getElementById('isoRunBtn');
            if(!btn)return;
            var speed=parseFloat(document.getElementById('isoSpeed').value);
            var hasSpeed=!isNaN(speed)&&speed>0;
            var hasIpp=!!ippMarker;
            btn.disabled=!(hasSpeed&&hasIpp);
        }

        /* Re-check the isochrone run button whenever speed input changes */
        (function(){
            var el=document.getElementById('isoSpeed');
            if(el)el.addEventListener('input',checkIsoRunButton);
        })();

        /**
         * Status bar helper for the isochrone section — mirrors
         * setAnalysisStatus and setIppStatus from the TARR workflow.
         */
        function setIsoStatus(type,msg){
            var bar=document.getElementById('isoStatusBar');
            bar.className='status-bar visible '+type;
            document.getElementById('isoStatusText').textContent=msg;
        }

        /**
         * Run the isochrone analysis pipeline.
         *
         * Collects IPP, speed (converted to km/h), selected time intervals,
         * and radius, then POSTs to /api/analyze-isochrone. The response
         * contains isochrone contour GeoJSON in the same structure as TARR
         * contours, so existing KML/GeoJSON/CalTopo export functions work
         * without modification.
         */
        function runIsochroneAnalysis(){
            if(!ippMarker){setIsoStatus('error','Place an IPP first.');return;}
            var speed=parseFloat(document.getElementById('isoSpeed').value);
            if(isNaN(speed)||speed<=0){setIsoStatus('error','Enter a valid travel speed.');return;}

            // Collect selected time intervals from checkboxes
            var intervals=[];
            document.querySelectorAll('.iso-interval:checked').forEach(function(cb){
                intervals.push(parseFloat(cb.value));
            });
            if(intervals.length===0){setIsoStatus('error','Select at least one time interval.');return;}

            var ipp=ippMarker.getLatLng();
            // No user-configurable radius — the backend auto-calculates
            // based on speed × max_hours × 1.5 + buffer
            var radius=10000;

            // Build the request payload — backend handles unit conversion
            // when speed_unit is 'mph'
            var params={
                ipp:{lat:ipp.lat,lng:ipp.lng},
                speed:speed,
                speed_unit:isoSpeedUnit,
                intervals:intervals,
                radius:radius
            };

            var btn=document.getElementById('isoRunBtn');
            btn.disabled=true;
            if(window.onAnalysisStart)window.onAnalysisStart();

            // Progress messages — same pipeline steps as TARR mode
            var msgs=[
                'Calculating bounding box...',
                'Downloading elevation data (USGS 3DEP)...',
                'Downloading land cover data (NLCD)...',
                'Downloading trails, roads, power lines, and waterways (OSM)...',
                'Building friction surface from land cover...',
                'Burning in trails, roads, and power line corridors...',
                'Running anisotropic cost-distance from IPP (this is the slow step)...',
                'Extracting isochrone contours...'
            ];
            var msgIdx=0;
            setIsoStatus('info',msgs[0]);
            var progressTimer=setInterval(function(){
                msgIdx++;
                if(msgIdx<msgs.length){setIsoStatus('info',msgs[msgIdx]);}
                else{setIsoStatus('info','Still processing... almost there.');}
            },8000);

            // POST to the isochrone endpoint
            fetch('/api/analyze-isochrone',{
                method:'POST',
                headers:{'Content-Type':'application/json'},
                body:JSON.stringify(params)
            }).then(function(r){return r.json();}).then(function(data){
                clearInterval(progressTimer);
                if(data.status!=='ok')throw new Error(data.message);

                setIsoStatus('success','Travel time analysis complete. '+
                    data.contour_geojson.features.length+' contours generated.');
                renderDataWarnings('isoDataWarnings',data.warnings||[]);

                // --- Render results on the map ---
                // Reuse the same layer toggle and download infrastructure as TARR mode
                document.getElementById('downloadSection').classList.remove('hidden');
                document.getElementById('dlCostPng').href='/api/results/'+data.analysis_id+'/cost_surface.png';
                document.getElementById('dlTerrainPng').href='/api/results/'+data.analysis_id+'/terrain.png';
                document.getElementById('dlCostDist').href='/api/results/'+data.analysis_id+'/cost_distance.tif';
                document.getElementById('dlCostSurf').href='/api/results/'+data.analysis_id+'/cost_surface.tif';

                // Isochrone mode has no probability surface or percentile PNGs
                document.getElementById('dlPctPng').style.display='none';
                document.getElementById('dlProb').style.display='none';

                // Relabel UI elements for travel time mode — these are hardcoded
                // as TARR labels in the HTML, so we update their text dynamically
                document.getElementById('pctToggle').parentElement.lastChild.textContent=' Travel Time Contours';
                document.getElementById('dlContoursKml').textContent='Travel Time Contours (KML)';
                document.getElementById('dlContoursGeojson').textContent='Travel Time Contours (GeoJSON)';
                document.getElementById('exportTarrsBtn').textContent='Export Contours to CalTopo';

                // Store contour GeoJSON for KML/GeoJSON export functions
                if(data.contour_geojson){
                    window._contourGeojson=data.contour_geojson;
                    document.getElementById('dlContoursKml').style.display='block';
                    document.getElementById('dlContoursGeojson').style.display='block';
                    // CalTopo export works for isochrones too — same polygon format
                    document.getElementById('caltopoExportSection').style.display='block';
                    document.getElementById('exportTarrsBtn').style.display='block';
                    document.getElementById('caltopoExportMapIdRow').style.display='block';
                }


                // --- Map overlays ---
                var bounds=[[data.bounds.south,data.bounds.west],[data.bounds.north,data.bounds.east]];
                if(window.costOverlay)map.removeLayer(window.costOverlay);
                if(window.pctOverlay)map.removeLayer(window.pctOverlay);
                if(window.terrainOverlay)map.removeLayer(window.terrainOverlay);
                contourLayer.clearLayers();

                var aid=data.analysis_id;

                /* Render the Jacobs Pure heatmap UNDER the isochrone polygons.
                   The heatmap conveys terrain-attractor priority (Jacobs 2015),
                   so even within a single isochrone band the coordinator can see
                   where trails, stream-trail intersections, and low pockets sit.
                   The heatmap is added to the map BEFORE the contour layer below
                   so that Leaflet's default z-order keeps the contour outlines
                   and labels on top, fully visible against the underlay. */
                window.costOverlay=L.imageOverlay('/api/results/'+aid+'/cost_surface.png?t='+Date.now(),bounds,{opacity:0.6});
                window.costOverlay.addTo(map);
                window.terrainOverlay=L.imageOverlay('/api/results/'+aid+'/terrain.png?t='+Date.now(),bounds,{opacity:0.6});

                if(data.contour_geojson){
                contourLayer.clearLayers();
                var feats=data.contour_geojson.features; // sorted small → large

                /* Render each contour with a dark halo underneath so it reads
                   clearly against the Jacobs heatmap. Draw in reverse order
                   (largest first, smallest last) so the innermost contour's
                   colored line ends up topmost. For each contour we add the
                   halo then the colored line as a pair, preserving z-order:
                   halo[12h] -> line[12h] -> halo[10h] -> line[10h] -> ... -> line[2h]. */
                var reversed=feats.slice().reverse(); // large → small
                reversed.forEach(function(f){
                    // Dark halo underneath — wider, semi-transparent black
                    var halo={color:'#1a1a1a',weight:6,opacity:0.6,fillOpacity:0};
                    contourLayer.addLayer(L.geoJSON(f,{style:halo}));
                    // Colored line on top
                    var style={
                        color:f.properties.color,
                        weight:3,
                        opacity:1.0,
                        fillOpacity:0
                    };
                    var layer=L.geoJSON(f,{style:style});
                    contourLayer.addLayer(layer);
                });

                // Add labels in normal order (small → large) so they layer nicely
                feats.forEach(function(f){
                    var labelText=f.properties.label||f.properties.hours+'h';
                    var ring=f.geometry.type==='Polygon'?f.geometry.coordinates[0]:f.geometry.coordinates[0][0];
                    var eastLng=-Infinity,eastLat=0;
                    ring.forEach(function(c){if(c[0]>eastLng){eastLng=c[0];eastLat=c[1];}});

                    var labelIcon=L.divIcon({
                        className:'',
                        html:'<div style="background:rgba(30,30,30,0.75);color:'+f.properties.color+';padding:4px 12px;border-radius:4px;font-size:13px;font-weight:700;font-family:sans-serif;white-space:nowrap;letter-spacing:0.5px;line-height:1;text-align:center;min-width:36px;border:1px solid '+f.properties.color+';">'+labelText+'</div>',
                        iconSize:[null,null],
                        iconAnchor:[-6,10]
                    });
                    contourLayer.addLayer(L.marker([eastLat,eastLng],{icon:labelIcon,interactive:false}));
                });

                /* Update the map legend to show travel time contour swatches.
                   The heatmap underneath conveys terrain-attractor priority
                   (Jacobs 2015), so the legend names both inputs. */
                var legendBody=document.getElementById('legendBody');
                if(legendBody){
                    var html='<div style="font-size:12px;font-weight:600;color:var(--text-primary);margin-bottom:8px;">Terrain attractor priority</div>';
                    html+='<div style="display:flex;gap:10px;margin-bottom:10px;"><canvas id="legendGradient" width="16" height="90" style="border-radius:3px;border:1px solid var(--border);"></canvas><div style="display:flex;flex-direction:column;justify-content:space-between;font-size:12px;color:var(--text-muted);"><span>High</span><span>Low</span></div></div>';
                    html+='<div style="border-top:1px solid var(--border);padding-top:8px;margin-top:4px;"><div style="font-size:12px;font-weight:600;color:var(--text-primary);margin-bottom:6px;">Travel time contours</div>';
                    feats.forEach(function(f){
                        html+='<div class="legend-row" style="margin-bottom:5px;"><span class="legend-swatch" style="background:'+f.properties.color+';height:3px;"></span><span style="color:'+f.properties.color+';font-weight:600;">'+f.properties.label+'</span></div>';
                    });
                    html+='</div><div style="border-top:1px solid var(--border);padding-top:6px;margin-top:8px;font-size:12px;color:var(--text-muted);line-height:1.4;">Color = per-pixel terrain attractor strength (Jacobs 2015). Contour boundaries show the maximum extent a subject could physically reach from the IPP at the given travel speed, based on the anisotropic cost-distance model.</div>';
                    legendBody.innerHTML=html;
                    // Re-paint the gradient canvas since we just replaced the legend's
                    // contents. paintLegendGradient is a no-op if the canvas is hidden.
                    if(typeof paintLegendGradient==='function')paintLegendGradient();
                }
                } // end if(data.contour_geojson)

                map.fitBounds(bounds);

                // Layer toggles — heatmap now renders under isochrones as default,
                // so the cost-surface toggle is on and enabled in this mode too.
                document.getElementById('layerToggles').classList.remove('hidden');
                document.getElementById('costToggle').checked=true;
                document.getElementById('costToggle').parentElement.style.opacity='1';
                document.getElementById('pctToggle').checked=true;
                document.getElementById('pctToggle').disabled=false;
                document.getElementById('pctToggle').parentElement.style.opacity='1';

                // Accordion: show Analysis Results section
                setSectionStatus('accIsochrone','done');
                setSectionStatus('accAnalysis','done');
                document.getElementById('accAnalysisSummary').textContent='Complete';
                var speedLabel=speed+' '+isoSpeedUnit+', '+intervals.length+' intervals';
                document.getElementById('accIsochroneSummary').textContent=speedLabel;
                collapseSection('accIsochrone',speedLabel);
                focusSection('accAnalysis');

                btn.disabled=false;
            }).catch(function(err){
                clearInterval(progressTimer);
                setIsoStatus('error','Failed: '+err.message);
                btn.disabled=false;
            });
        }
